            return parentWritable
        }
        return parentWritable && fileManager.isWritableFile(atPath: bundlePath)
    }

    // MARK: - Script templates

    private static func manualSwapScript(
        stagedAppPath: String,
        bundlePath: String,
        parentPID: Int32,
        logPath: String
