import SwiftUI
import AIUsagesTrackersLib

struct UpdatesSettingsView: View {
    let preferences: any AppPreferences
    let updateState: UpdateState

    private static let lastCheckedFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateStyle = .medium
        f.timeStyle = .short
        return f
    }()

    private var currentVersionString: String {
        AppDelegate.currentAppVersionLabel()
    }

    private var installationKindLabel: String? {
        switch updateState.installationKind {
        case .homebrewCask: return "Homebrew cask"
        case .manual: return "Manual install"
        case .none: return nil
        }
    }

    var body: some View {
        let prefs = AppDelegate.sharedPreferences
        Form {
            Section("Current version") {
                HStack {
                    Text("Installed version")
                    Spacer()
                    Text(currentVersionString)
                        .font(.system(.body, design: .monospaced))
                        .foregroundStyle(.secondary)
                        .textSelection(.enabled)
                }
                HStack {
                    Text("Installation type")
                    Spacer()
                    Text(installationKindLabel ?? "—")
                        .foregroundStyle(.secondary)
                }
            }

            Section("Automatic updates") {
                Toggle("Check for updates automatically", isOn: Binding(
                    get: { prefs.updatesAutoCheckEnabled },
                    set: { prefs.updatesAutoCheckEnabled = $0 }
                ))
                Text("When enabled, AI Usages Tracker checks GitHub for new releases at startup and every six hours.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }

            Section("Manual check") {
                HStack {
                    Button("Check now") {
                        Task {
                            await AppDelegate.sharedUpdateScheduler?.checkNow()
                        }
                    }
                    .disabled(updateState.phase == .checking)

                    if updateState.phase == .checking {
                        ProgressView().controlSize(.small).scaleEffect(0.7)
                    }
                    Spacer()
                    if let last = updateState.lastCheckedAt {
                        Text("Last checked \(Self.lastCheckedFormatter.string(from: last))")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                }
                if let pending = updateState.pendingUpdate {
                    Text("Version \(pending.version.rawValue) is available.")
                        .font(.caption)
                        .foregroundStyle(.green)
                } else if updateState.lastError != nil {
                    Text("Last check failed: \(updateState.lastError ?? "")")
                        .font(.caption)
                        .foregroundStyle(.red)
                } else if updateState.lastCheckedAt != nil {
                    Text("You are up to date.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }

            if let available = updateState.availableUpdate {
                Section("Install update") {
                    VStack(alignment: .leading, spacing: 8) {
                        HStack {
                            VStack(alignment: .leading, spacing: 2) {
                                Text("Version \(available.version.rawValue) ready to install")
                                Text(updateState.installationKind == .homebrewCask
                                     ? "Will run `brew upgrade --cask`."
                                     : "Will download and replace the app bundle.")
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            }
                            Spacer()
                            primaryActionButton
                        }
                        installProgressView
                    }
                }
            }

            if !prefs.updatesDismissedVersions.isEmpty {
                Section("Skipped versions") {
                    ForEach(prefs.updatesDismissedVersions, id: \.self) { version in
                        HStack {
                            Text(version).font(.system(size: 12))
                            Spacer()
                            Button(role: .destructive) {
                                prefs.updatesDismissedVersions.removeAll { $0 == version }
                                updateState.dismissedVersions.remove(version)
                            } label: {
                                Image(systemName: "trash")
                            }
                            .buttonStyle(.borderless)
                        }
                    }
                }
            }
        }
        .formStyle(.grouped)
    }

    @ViewBuilder
    private var primaryActionButton: some View {
        if updateState.isReadyToRestart {
            Button("Restart now") {
                AppDelegate.sharedTriggerRestart?()
            }
            .buttonStyle(.borderedProminent)
        } else {
            Button(updateState.installationKind == .homebrewCask
                   ? "Install via Homebrew"
                   : "Download and install") {
                AppDelegate.sharedTriggerUpdateInstall?()
            }
            .disabled(updateState.isInstallInProgress)
        }
    }

    @ViewBuilder
    private var installProgressView: some View {
        switch updateState.phase {
        case .preparing:
            HStack(spacing: 6) {
                ProgressView().controlSize(.small).scaleEffect(0.7)
                Text("Preparing…").font(.caption).foregroundStyle(.secondary)
            }
        case .downloading(let received, let total):
            VStack(alignment: .leading, spacing: 4) {
                if let total, total > 0 {
                    ProgressView(value: Double(received), total: Double(total))
                        .progressViewStyle(.linear)
                } else {
                    ProgressView().progressViewStyle(.linear)
                }
                Text(Self.formatBytes(received: received, total: total))
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
        case .verifying:
            progressLabel("Verifying download…")
        case .extracting:
            progressLabel("Extracting…")
        case .runningHomebrew(let line):
            VStack(alignment: .leading, spacing: 4) {
                progressLabel("Running brew upgrade…")
                if let line, !line.isEmpty {
                    Text(line)
                        .font(.system(size: 10, design: .monospaced))
                        .foregroundStyle(.secondary)
                        .lineLimit(1)
                        .truncationMode(.middle)
                }
            }
        case .restarting:
            progressLabel("Restarting…")
        case .failed(let message):
            Text("Failed: \(message)")
                .font(.caption)
                .foregroundStyle(.red)
                .lineLimit(3)
        case .idle, .checking, .readyToRestart:
            EmptyView()
        }
    }

    private func progressLabel(_ text: String) -> some View {
        HStack(spacing: 6) {
            ProgressView().controlSize(.small).scaleEffect(0.7)
            Text(text).font(.caption).foregroundStyle(.secondary)
        }
    }

    private static func formatBytes(received: Int64, total: Int64?) -> String {
        let formatter = ByteCountFormatter()
        formatter.allowedUnits = [.useMB, .useKB, .useGB]
        formatter.countStyle = .file
        let receivedStr = formatter.string(fromByteCount: received)
        if let total, total > 0 {
            return "\(receivedStr) of \(formatter.string(fromByteCount: total))"
        }
        return receivedStr
    }
}

import SwiftUI
import AIUsagesTrackersLib

struct UpdateAvailableBanner: View {
    let update: AvailableUpdate
    let installationKind: InstallationKind?
    let phase: UpdateState.Phase
    let onInstall: () -> Void
    let onRestart: () -> Void
    let onSkip: () -> Void
    let onLater: () -> Void

    private var primaryActionLabel: String {
        switch installationKind {
        case .homebrewCask: return "Update via Homebrew"
        case .manual, .none: return "Install update"
        }
    }

    private var subtitle: String {
        switch installationKind {
        case .homebrewCask:
            return "A new version is available. AI Usages Tracker will be reinstalled via Homebrew."
        case .manual, .none:
            return "A new version is available. macOS may ask for your administrator password if the app lives in a protected location."
        }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(spacing: 6) {
                Image(systemName: bannerIconName)
                    .foregroundStyle(.tint)
                Text(bannerTitle)
                    .font(.system(size: 11, weight: .bold))
                    .textCase(.uppercase)
                Spacer()
                Text(update.version.rawValue)
                    .font(.system(size: 11, weight: .semibold))
                    .foregroundStyle(.secondary)
            }

            switch phase {
            case .preparing, .downloading, .verifying, .extracting, .runningHomebrew:
                inProgressSection
            case .readyToRestart:
                readyToRestartSection
            case .restarting:
                restartingSection
            case .failed(let message):
                failureSection(message: message)
            case .idle, .checking:
                idleSection
            }
        }
        .padding(8)
        .background(Color.accentColor.opacity(0.10), in: RoundedRectangle(cornerRadius: 6))
        .overlay(
            RoundedRectangle(cornerRadius: 6)
                .strokeBorder(Color.accentColor.opacity(0.30), lineWidth: 1)
        )
    }

    // MARK: - Sections

    private var idleSection: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(subtitle)
                .font(.system(size: 11))
                .foregroundStyle(.secondary)
                .fixedSize(horizontal: false, vertical: true)

            HStack(spacing: 8) {
                Button(primaryActionLabel) { onInstall() }
                    .buttonStyle(.borderedProminent)
                    .controlSize(.small)

                Button("Later") { onLater() }
                    .buttonStyle(.bordered)
                    .controlSize(.small)

                Spacer()

                Button {
                    NSWorkspace.shared.open(update.releaseURL)
                } label: {
                    Image(systemName: "arrow.up.right.square")
                }
                .buttonStyle(.borderless)
                .help("Open release notes")

                Button {
                    onSkip()
                } label: {
                    Text("Skip")
                        .font(.system(size: 11))
                }
                .buttonStyle(.borderless)
                .help("Skip this version")
            }
        }
    }

    private var inProgressSection: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(spacing: 6) {
                ProgressView().controlSize(.small).scaleEffect(0.7)
                Text(progressStatusText)
                    .font(.system(size: 11))
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
                    .truncationMode(.middle)
                Spacer()
            }
            if let fraction = downloadProgressFraction {
                ProgressView(value: fraction)
                    .progressViewStyle(.linear)
            } else if case .downloading = phase {
                ProgressView()
                    .progressViewStyle(.linear)
            }
            if let detail = progressDetailText {
                Text(detail)
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
                    .truncationMode(.tail)
            }
        }
    }

    private var readyToRestartSection: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text("Update ready. Click Restart to apply it now.")
                .font(.system(size: 11))
                .foregroundStyle(.secondary)
                .fixedSize(horizontal: false, vertical: true)

            HStack(spacing: 8) {
                Button("Restart now") { onRestart() }
                    .buttonStyle(.borderedProminent)
                    .controlSize(.small)
                Button("Later") { onLater() }
                    .buttonStyle(.bordered)
                    .controlSize(.small)
                Spacer()
            }
        }
    }

    private var restartingSection: some View {
        HStack(spacing: 6) {
            ProgressView().controlSize(.small).scaleEffect(0.7)
            Text("Restarting…")
                .font(.system(size: 11))
                .foregroundStyle(.secondary)
            Spacer()
        }
    }

    private func failureSection(message: String) -> some View {
        VStack(alignment: .leading, spacing: 6) {
            Text("Update failed")
                .font(.system(size: 11, weight: .semibold))
                .foregroundStyle(.red)
            Text(message)
                .font(.system(size: 10))
                .foregroundStyle(.secondary)
                .lineLimit(3)
                .fixedSize(horizontal: false, vertical: true)
            HStack(spacing: 8) {
                Button("Retry") { onInstall() }
                    .buttonStyle(.borderedProminent)
                    .controlSize(.small)
                Button("Later") { onLater() }
                    .buttonStyle(.bordered)
                    .controlSize(.small)
                Spacer()
            }
        }
    }

    // MARK: - Helpers

    private var bannerIconName: String {
        switch phase {
        case .failed: return "exclamationmark.triangle.fill"
        case .readyToRestart: return "checkmark.circle.fill"
        default: return "arrow.down.circle.fill"
        }
    }

    private var bannerTitle: String {
        switch phase {
        case .failed: return "Update failed"
        case .readyToRestart: return "Update ready"
        case .restarting: return "Restarting"
        case .preparing, .downloading, .verifying, .extracting, .runningHomebrew: return "Updating"
        case .idle, .checking: return "Update available"
        }
    }

    private var progressStatusText: String {
        switch phase {
        case .preparing: return "Preparing…"
        case .downloading: return "Downloading update…"
        case .verifying: return "Verifying download…"
        case .extracting: return "Extracting…"
        case .runningHomebrew: return "Running brew upgrade…"
        default: return ""
        }
    }

    private var progressDetailText: String? {
        switch phase {
        case .downloading(let received, let total):
            return Self.formatBytesProgress(received: received, total: total)
        case .runningHomebrew(let line):
            return line
        default:
            return nil
        }
    }

    private var downloadProgressFraction: Double? {
        if case .downloading(let received, let total) = phase, let total, total > 0 {
            return min(1.0, max(0.0, Double(received) / Double(total)))
        }
        return nil
    }

    private static func formatBytesProgress(received: Int64, total: Int64?) -> String {
        let formatter = ByteCountFormatter()
        formatter.allowedUnits = [.useMB, .useKB, .useGB]
        formatter.countStyle = .file
        let receivedStr = formatter.string(fromByteCount: received)
        if let total, total > 0 {
            let totalStr = formatter.string(fromByteCount: total)
            return "\(receivedStr) of \(totalStr)"
        }
        return receivedStr
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// Scrollable popover anchored to the menu bar item; uses LazyVStack + maxHeight
/// so the popover does not stretch unboundedly when many accounts are present.
struct UsageDetailsView: View {
    let store: UsageStore
    let refreshState: RefreshState
    let historyReader: UsageHistoryReader
    let updateState: UpdateState
    let onRefresh: () async -> Void
    let onOpenSettings: () -> Void
    let onQuit: () -> Void
    let onInstallUpdate: () -> Void
    let onRestartUpdate: () -> Void
    let onSkipUpdate: () -> Void
    let onLaterUpdate: () -> Void

    @State private var contentMode: PopoverContentMode = .list
    @State private var selectedHistoryWindow: UsageHistoryTimeWindow = .twentyFourHours
    @State private var historySnapshot: UsageHistorySnapshot = .empty
    @State private var historyReferenceDate = Date()
    @State private var historyWindowOffset: Int = 0
    @State private var isLoadingHistory = false

    private static let popoverWidth: CGFloat = 320
    private static let maxScreenHeightRatio: CGFloat = 0.9
    private static let fallbackScreenHeight: CGFloat = 800
    private static let historyAutoRefreshInterval: Duration = .seconds(60)
    /// Reserved for header + footer + dividers so the full popover stays within the ratio cap.
    private static let chromeHeightReserve: CGFloat = 80

    private var maxScrollHeight: CGFloat {
        let screenHeight = NSScreen.main?.visibleFrame.height ?? Self.fallbackScreenHeight
        return screenHeight * Self.maxScreenHeightRatio - Self.chromeHeightReserve
    }

    var body: some View {
        VStack(spacing: 0) {
            header

            Divider()

            if let pending = updateState.pendingUpdate {
                UpdateAvailableBanner(
                    update: pending,
                    installationKind: updateState.installationKind,
                    phase: updateState.phase,
                    onInstall: onInstallUpdate,
                    onRestart: onRestartUpdate,
                    onSkip: onSkipUpdate,
                    onLater: onLaterUpdate
                )
                .padding(.horizontal, 12)
                .padding(.vertical, 8)
                Divider()
            }

            content

            Divider()

            footer
        }
        .frame(width: Self.popoverWidth)
        .task(id: historyTaskID) {
            await runHistoryRefreshLoopIfNeeded()
        }
    }

    private var historyTaskID: String {
        "\(contentMode.rawValue)-\(selectedHistoryWindow.rawValue)"
    }

    /// Returns a map of vendor → first index in sorted, for vendors that have active outages.
    private func vendorsNeedingBanner(in sorted: [VendorUsageEntry]) -> [Vendor: Int] {
        var result: [Vendor: Int] = [:]
        for (index, entry) in sorted.enumerated() where result[entry.vendor] == nil {
            if store.outagesByVendor[entry.vendor] != nil {
                result[entry.vendor] = index
            }
        }
        return result
    }

    // MARK: - Subviews

    @ViewBuilder
    private var content: some View {
        switch contentMode {
        case .list:
            listingContent
        case .chart:
            chartContent
        }
    }

    @ViewBuilder
    private var listingContent: some View {
        let prefs = AppDelegate.sharedPreferences
        let sorted = store.entries
            .excluding(ignoredAccounts: prefs.ignoredAccounts)
            .sortedForDisplay()
        if sorted.isEmpty && !store.entries.isEmpty {
            allAccountsIgnoredState
        } else if sorted.isEmpty {
            emptyState
        } else {
            ScrollView {
                LazyVStack(spacing: 8) {
                    // Track which vendors have already shown their status banner
                    // using a running cursor — entries are sorted by vendor so
                    // entries of the same vendor are contiguous.
                    let vendorsWithBanner = vendorsNeedingBanner(in: sorted)
                    ForEach(Array(sorted.enumerated()), id: \.element.id) { index, entry in
                        if vendorsWithBanner[entry.vendor] == index,
                           let outages = store.outagesByVendor[entry.vendor] {
                            VendorStatusBanner(outages: outages)
                        }
                        AccountCardView(
                            entry: entry,
                            isRefreshing: refreshState.isRefreshing(
                                vendor: entry.vendor,
                                account: entry.account
                            ),
                            onIgnore: {
                                let ignored = IgnoredAccount(vendor: entry.vendor, account: entry.account)
                                if !prefs.ignoredAccounts.contains(ignored) {
                                    prefs.ignoredAccounts.append(ignored)
                                }
                            }
                        )
                    }
                }
                .padding(12)
            }
            .frame(maxHeight: maxScrollHeight)
            .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
        }
    }

    private var chartContent: some View {
        ScrollView {
            UsageHistoryChartView(
                snapshot: historySnapshot,
                referenceDate: historyReferenceDate,
                selectedWindow: historyWindowBinding,
                isLoading: isLoadingHistory,
                configurations: AppDelegate.sharedPreferences.chartConfigurations,
                currentEntries: store.entries,
                onPreviousWindow: {
                    Task { await moveHistoryWindow(direction: .previous) }
                },
                onNextWindow: {
                    Task { await moveHistoryWindow(direction: .next) }
                }
            )
        }
        .frame(maxHeight: maxScrollHeight)
        .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
    }

    private var historyWindowBinding: Binding<UsageHistoryTimeWindow> {
        Binding(
            get: { selectedHistoryWindow },
            set: { newValue in
                selectedHistoryWindow = newValue
                historyWindowOffset = 0
            }
        )
    }

    private var header: some View {
        let refreshing = !refreshState.inFlight.isEmpty
        return HStack(spacing: 8) {
            Button {
                onOpenSettings()
            } label: {
                Image(systemName: "gearshape")
                    .frame(width: 16, height: 16)
                    .hoverAffordance()
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .help("Settings")
            .keyboardShortcut(",", modifiers: .command)
            .focusable(false)

            Spacer()

            Text("AI Usages Tracker")
                .font(.system(size: 11, weight: .medium))
                .foregroundStyle(.secondary)

            Spacer()

            Button {
                guard !refreshing else { return }
                Task { await onRefresh() }
            } label: {
                ZStack {
                    if refreshing {
                        ProgressView()
                            .controlSize(.small)
                            .scaleEffect(0.6)
                    } else {
                        Image(systemName: "arrow.clockwise")
                    }
                }
                .frame(width: 16, height: 16)
                .hoverAffordance(isEnabled: !refreshing)
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .disabled(refreshing)
            .help("Refresh usage data")
            .keyboardShortcut("r")
            .focusable(false)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }

    private var allAccountsIgnoredState: some View {
        VStack(spacing: 8) {
            Text("All accounts are hidden")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.secondary)
            Text("Remove ignored accounts in Settings to restore visibility.")
                .font(.system(size: 11))
                .foregroundStyle(.tertiary)
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 32)
        .padding(.horizontal, 24)
    }

    @ViewBuilder
    private var emptyState: some View {
        if AppDelegate.sharedPreferences.menuBarSegments.isEmpty {
            unconfiguredEmptyState
        } else {
            VStack(spacing: 8) {
                Text("No usage data")
                    .font(.system(size: 12, weight: .medium))
                    .foregroundStyle(.secondary)
                Text("Waiting for data...")
                    .font(.system(size: 11))
                    .foregroundStyle(.tertiary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 32)
        }
    }

    private var unconfiguredEmptyState: some View {
        VStack(spacing: 12) {
            Image(systemName: "gearshape.2")
                .font(.system(size: 28, weight: .light))
                .foregroundStyle(.secondary)
            Text("No menu bar segment yet")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.primary)
            Text("Add your first segment to start tracking your AI usages directly from the menu bar.")
                .font(.system(size: 11))
                .foregroundStyle(.secondary)
                .multilineTextAlignment(.center)
                .fixedSize(horizontal: false, vertical: true)
            Button {
                onOpenSettings()
            } label: {
                Text("Open Settings")
            }
            .controlSize(.small)
        }
        .frame(maxWidth: .infinity)
        .padding(.horizontal, 24)
        .padding(.vertical, 24)
    }

    private var footer: some View {
        HStack {
            Picker("Popover content", selection: $contentMode) {
                Image(systemName: "list.bullet")
                    .tag(PopoverContentMode.list)
                Image(systemName: "chart.xyaxis.line")
                    .tag(PopoverContentMode.chart)
            }
            .pickerStyle(.segmented)
            .labelsHidden()
            .controlSize(.mini)
            .frame(width: 62)
            .help("Switch between usage list and history chart")
            .focusable(false)

            Spacer()

            Button {
                onQuit()
            } label: {
                Text("Quit")
                    .hoverAffordance()
            }
            .buttonStyle(.borderless)
            .keyboardShortcut("q")
            .controlSize(.small)
            .focusable(false)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }

    @MainActor
    private func runHistoryRefreshLoopIfNeeded() async {
        guard contentMode == .chart else { return }
        while !Task.isCancelled {
            await loadHistory()
            do {
                try await Task.sleep(for: Self.historyAutoRefreshInterval)
            } catch {
                break
            }
        }
    }

    private func computeReferenceDate() -> Date {
        guard historyWindowOffset > 0,
              let interval = selectedHistoryWindow.timeInterval else {
            return Date()
        }
        return Date().addingTimeInterval(-Double(historyWindowOffset) * interval)
    }

    @MainActor
    private func loadHistory() async {
        let requestedWindow = selectedHistoryWindow
        let requestedOffset = historyWindowOffset
        let requestedDate = computeReferenceDate()
        isLoadingHistory = true
        let snapshot = await historyReader.load(window: requestedWindow, now: requestedDate)
        guard contentMode == .chart,
              selectedHistoryWindow == requestedWindow,
              historyWindowOffset == requestedOffset else {
            isLoadingHistory = false
            return
        }
        historySnapshot = snapshot
        historyReferenceDate = requestedDate
        isLoadingHistory = false
    }

    @MainActor
    private func moveHistoryWindow(direction: HistoryWindowDirection) async {
        guard selectedHistoryWindow.timeInterval != nil else { return }
        switch direction {
        case .previous:
            historyWindowOffset += 1
        case .next:
            guard historyWindowOffset > 0 else { return }
            historyWindowOffset -= 1
        }
        await loadHistory()
    }
}

private enum PopoverContentMode: String, Hashable {
    case list
    case chart
}

private enum HistoryWindowDirection {
    case previous
    case next
}

